import{_ as t,o,c as n,ag as a}from"./chunks/framework.BBBcTwIo.js";const u=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/installation.md","filePath":"guide/installation.md"}'),i={name:"guide/installation.md"};function s(r,e,l,d,c,g){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><h2 id="unity-version" tabindex="-1">Unity version <a class="header-anchor" href="#unity-version" aria-label="Permalink to &quot;Unity version&quot;">​</a></h2><p>Event Monitor is built and tested with <strong>Unity 6 LTS</strong> (for example <code>6000.3.7f1</code>). The package relies on Unity’s <strong>IL Post-Processor</strong> pipeline, which is available in modern Unity versions. If you use an older editor, verify ILPP support before relying on automatic instrumentation.</p><h2 id="package-layout" tabindex="-1">Package layout <a class="header-anchor" href="#package-layout" aria-label="Permalink to &quot;Package layout&quot;">​</a></h2><p>Add the Event Monitor package to your project using <strong>Unity Package Manager</strong> (git URL, tarball, or embedded folder), following your team’s usual workflow. The package typically contains:</p><ul><li><strong>Runtime</strong> — <code>EventBus</code>, <code>EventRecord</code>, optional <code>ReflectionScanner</code>.</li><li><strong>Editor</strong> — <code>EventMonitor</code> window, settings, demo scene tooling.</li><li><strong>IL Post-Processors</strong> — assembly that rewrites user assemblies at compile time.</li></ul><p>Exact folder names may vary by version; treat this documentation as product-level guidance.</p><h2 id="dependency-mono-cecil" tabindex="-1">Dependency: Mono.Cecil <a class="header-anchor" href="#dependency-mono-cecil" aria-label="Permalink to &quot;Dependency: Mono.Cecil&quot;">​</a></h2><p>The IL post-processor depends on <strong>Mono.Cecil</strong>, commonly pulled in via Unity’s package:</p><ul><li><code>com.unity.nuget.mono-cecil</code> (for example <code>1.11.6</code>)</li></ul><p>Ensure it resolves without conflicts in <strong>Package Manager</strong>.</p><h2 id="which-assemblies-get-instrumented" tabindex="-1">Which assemblies get instrumented? <a class="header-anchor" href="#which-assemblies-get-instrumented" aria-label="Permalink to &quot;Which assemblies get instrumented?&quot;">​</a></h2><p>The post-processor <strong>does not</strong> rewrite every DLL in your project. Typical <strong>user</strong> script assemblies (for example <code>Assembly-CSharp</code> and many custom <strong>asmdef</strong> assemblies) are candidates. <strong>Unity engine</strong>, <strong>Editor</strong>, <strong>system</strong>, and <strong>Event Monitor’s own</strong> assemblies are skipped to avoid recursion and noise.</p><p>If your gameplay code lives in a <strong>custom asmdef</strong>, that assembly is usually still processed as long as it is allow-listed by the tool’s gate and recording is enabled. See <a href="./../how-to/ilpp-diagnostics.html">ILPP diagnostics and settings</a> and <a href="./../reference/il-limitations.html">IL patterns and limitations</a>.</p><h2 id="verify-instrumentation" tabindex="-1">Verify instrumentation <a class="header-anchor" href="#verify-instrumentation" aria-label="Permalink to &quot;Verify instrumentation&quot;">​</a></h2><p>After installation:</p><ol><li>Open <strong>Window → Event Monitor</strong> and enable <strong>Record</strong>.</li><li>Enter <strong>Play Mode</strong> and trigger a known <code>event +=</code> / <code>?.Invoke()</code> path.</li><li>Confirm <strong>SUB</strong> / <strong>INVOKE</strong> rows appear.</li></ol><p>If nothing appears, use <a href="./../troubleshooting/faq.html">Troubleshooting &amp; FAQ</a> and optional ILPP diagnostics.</p><h2 id="next-step" tabindex="-1">Next step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next step&quot;">​</a></h2><p>Continue with <a href="./quick-start.html">Quick Start</a>.</p>',20)])])}const h=t(i,[["render",s]]);export{u as __pageData,h as default};
